Here's a complete test class using modern MSTest 3.x patterns with proper cancellation/timeout handling:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, FakeHandler handler) CreateFetcher(
        HttpStatusCode statusCode = HttpStatusCode.OK,
        string content = "response-body")
    {
        var handler = new FakeHandler(statusCode, content);
        var client = new HttpClient(handler);
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        var (fetcher, _) = CreateFetcher(content: "hello world");

        var result = await fetcher.FetchAsync(
            "https://example.com/data", _testContext.CancellationToken);

        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.NotFound);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/missing", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceledException()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var (fetcher, _) = CreateFetcher();

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_Timeout_IsCancelledCooperatively()
    {
        // Handler delays longer than the test timeout
        var handler = new FakeHandler(HttpStatusCode.OK, "slow") { Delay = TimeSpan.FromSeconds(30) };
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // TestContext.CancellationToken fires when [Timeout] expires
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/slow", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_PassesUrlToHandler()
    {
        var (fetcher, handler) = CreateFetcher();

        await fetcher.FetchAsync(
            "https://example.com/api/items", _testContext.CancellationToken);

        Assert.AreEqual("https://example.com/api/items", handler.LastRequestUri?.ToString());
    }

    // Minimal fake handler — no mocking library needed
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpStatusCode _statusCode;
        private readonly string _content;

        public TimeSpan Delay { get; set; }
        public Uri? LastRequestUri { get; private set; }

        public FakeHandler(HttpStatusCode statusCode, string content)
        {
            _statusCode = statusCode;
            _content = content;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            LastRequestUri = request.RequestUri;

            if (Delay > TimeSpan.Zero)
                await Task.Delay(Delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content),
            };
        }
    }
}
```

**Key patterns used:**

- **`TestContext.CancellationToken`** — passed to all async calls so `[Timeout]` can cancel cooperatively instead of abandoning the thread
- **`[Timeout(ms)]` + slow handler** — tests that your code actually respects cancellation under timeout
- **Pre-cancelled token** — verifies immediate cancellation without waiting
- **`Assert.ThrowsExactlyAsync`** — modern exception testing (not `[ExpectedException]`)
- **`FakeHandler`** — lightweight `HttpMessageHandler` stub; avoids mocking libraries and lets you control status codes, content, and delays
- **Sealed class, constructor-injected `TestContext`** — MSTest 3.x best practices
